import fs from 'fs';
import dotenv from 'dotenv';
dotenv.config({ path: '.env.local' });

const baseUrl = process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000';

async function testFlow() {
    console.log("--- STARTING END-TO-END FLOW TEST ---");

    // 1. Test Tailor API directly (using text)
    console.log("\nStep 1: Testing /api/tailor (with retry/fallback testing)...");
    const tailorRes = await fetch(`${baseUrl}/api/tailor`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            originalResume: "John Doe. Experience: 5 years in React. Skills: JS, React, Node.",
            jobDescription: "Looking for a Senior React Developer with Node experience.",
            language: 'en',
            strength: 'balanced'
        })
    });

    if (!tailorRes.ok) {
        console.error("Tailor API Failed:", await tailorRes.text());
        return;
    }
    const tailorData = await tailorRes.json();
    console.log("Tailor API Success!");
    console.log("ATS Score:", tailorData.data.ats_score);
    console.log("Predicted Score:", tailorData.data.predicted_ats_score);

    // 2. Test PDF API
    console.log("\nStep 2: Testing /api/pdf...");
    const pdfRes = await fetch(`${baseUrl}/api/pdf`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
            htmlContent: tailorData.data.tailored_resume_html,
            template: 'modern'
        })
    });

    if (!pdfRes.ok) {
        console.error("PDF API Failed:", await pdfRes.text());
        return;
    }
    const pdfData = await pdfRes.json();
    console.log("PDF API Success! URL:", pdfData.url);

    console.log("\n--- FLOW TEST COMPLETED SUCCESSFULLY ---");
}

testFlow().catch(console.error);

import fs from 'fs';
import dotenv from 'dotenv';
dotenv.config({ path: '.env.local' });

const apiKey = process.env.GEMINI_API_KEY;
if (!apiKey) {
    console.error("No API Key found in .env.local");
    process.exit(1);
}

const model = "gemini-2.5-flash"; // Stable model from the list
const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`;

const payload = {
    contents: [{
        parts: [{ text: "Hello, tell me a short joke." }]
    }]
};

async function test() {
    console.log(`Testing Gemini API with model: ${model}...`);
    try {
        const res = await fetch(url, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(payload)
        });

        console.log(`Status: ${res.status} ${res.statusText}`);
        const data = await res.json();
        console.log("Response:", JSON.stringify(data, null, 2));
    } catch (err) {
        console.error("Fetch Error:", err);
    }
}

test();

import { redirect } from 'next/navigation';
import { getUser, isAdminEmail } from '@/lib/supabase/server';

export const dynamic = 'force-dynamic';

export default async function AdminDashboard({
  params,
}: {
  params: Promise<{ locale: string }>;
}) {
  const { locale } = await params;
  const user = await getUser();
  if (!user) {
    redirect(`/${locale}/auth/login`);
  }

  if (!isAdminEmail(user.email)) {
    redirect(`/${locale}/dashboard`);
  }

  // Fetch real logs from Supabase using service role if available
  const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL || '';
  const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || '';

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let logs: any[] = [];

  if (supabaseUrl && supabaseKey) {
    try {
      const { createClient } = await import('@supabase/supabase-js');
      const supabase = createClient(supabaseUrl, supabaseKey);
      const { data, error } = await supabase
        .from('audit_logs')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(100);
      if (!error && data && data.length > 0) {
        logs = data;
      }
    } catch {
      console.warn("Failed fetching audit_logs from Supabase.");
    }
  }

  // Only show demo data if no real data available
  if (logs.length === 0) {
    logs = [
      { id: '1', endpoint: '/api/parse', ip_hash: 'c4ca4238', latency: 345, created_at: new Date().toISOString(), status: '200' },
      { id: '2', endpoint: '/api/tailor', ip_hash: 'c81e728d', latency: 1240, created_at: new Date(Date.now() - 10000).toISOString(), status: '200' },
      { id: '3', endpoint: '/api/pdf', ip_hash: 'eccbc87e', latency: 50, created_at: new Date(Date.now() - 20000).toISOString(), status: '500' },
    ];
  }

  return (
    <div className="text-[#d7e3fc] p-6 lg:p-10">
      <header className="mb-8">
        <h1 className="text-2xl font-black tracking-tight uppercase text-[#6bd8cb]">Admin Overlook Protocol</h1>
        <p className="text-[#737679] text-sm mt-1.5">Monitors anonymized endpoint usage. No PII is logged.</p>
        <p className="text-[#45484c] text-xs mt-1 font-mono">Authenticated as: {user.email}</p>
      </header>

      {/* Stats Summary */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
        <div className="bg-[#101c2e] p-5 rounded-lg">
          <p className="text-xs text-[#737679] uppercase tracking-widest mb-1">Total Requests</p>
          <p className="text-2xl font-bold font-mono text-[#d7e3fc]">{logs.length}</p>
        </div>
        <div className="bg-[#101c2e] p-5 rounded-lg">
          <p className="text-xs text-[#737679] uppercase tracking-widest mb-1">Success Rate</p>
          <p className="text-2xl font-bold font-mono text-[#6bd8cb]">
            {logs.length > 0 ? Math.round((logs.filter(l => l.status === '200').length / logs.length) * 100) : 0}%
          </p>
        </div>
        <div className="bg-[#101c2e] p-5 rounded-lg">
          <p className="text-xs text-[#737679] uppercase tracking-widest mb-1">Avg Latency</p>
          <p className="text-2xl font-bold font-mono text-[#b8c4ff]">
            {logs.length > 0 ? Math.round(logs.reduce((a, l) => a + (l.latency || 0), 0) / logs.length) : 0}ms
          </p>
        </div>
      </div>

      {/* Logs Table */}
      <div className="bg-[#101c2e] p-6 rounded-lg overflow-x-auto">
        <table className="w-full text-left font-mono text-sm">
          <thead className="text-[#45474c]">
            <tr className="border-b border-[#1c2024]">
              <th className="py-3 font-normal tracking-widest uppercase text-xs">Route</th>
              <th className="font-normal tracking-widest uppercase text-xs">Hash</th>
              <th className="font-normal tracking-widest uppercase text-xs">Latency</th>
              <th className="font-normal tracking-widest uppercase text-xs">Timestamp</th>
              <th className="font-normal tracking-widest uppercase text-xs text-right">Status</th>
            </tr>
          </thead>
          <tbody>
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
            {logs.map((log: any) => (
              <tr key={log.id} className="border-b border-[#142032] hover:bg-[#142032] transition-colors">
                <td className="py-3 text-[#d7e3fc]">{log.endpoint}</td>
                <td className="text-[#737679]">{log.ip_hash?.substring(0, 8) || '—'}...</td>
                <td className="text-[#b8c4ff]">{log.latency ?? '—'}ms</td>
                <td className="text-[#45474c]">{new Date(log.created_at).toLocaleTimeString()}</td>
                <td className="text-right">
                  <span className={`px-2 py-0.5 text-xs rounded-sm font-bold ${log.status === '200' ? 'bg-[#004145] text-[#6bd8cb]' : 'bg-[#360001] text-[#ffb4ab]'}`}>
                    {log.status}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

import { Redis } from "@upstash/redis";
import crypto from 'crypto';

const redisUrl = process.env.UPSTASH_REDIS_REST_URL;
const redisToken = process.env.UPSTASH_REDIS_REST_TOKEN;

const redis = redisUrl && redisToken ? new Redis({ url: redisUrl, token: redisToken }) : null;

export function generateCacheKey(resume: string, jd: string, lang: string, strength: string): string {
    const hash = crypto.createHash('sha256');
    hash.update(`${resume}|${jd}|${lang}|${strength}`);
    return `tailor:v1:${hash.digest('hex')}`;
}

export async function getCachedTailoring(key: string): Promise<any | null> {
    if (!redis) return null;
    try {
        return await redis.get(key);
    } catch (e) {
        console.warn('[Cache] Redis get failed', e);
        return null;
    }
}

export async function setCachedTailoring(key: string, data: any): Promise<void> {
    if (!redis) return;
    try {
        // Cache for 24 hours (86400 seconds)
        await redis.set(key, data, { ex: 86400 });
    } catch (e) {
        console.warn('[Cache] Redis set failed', e);
    }
}

import { AtsTailorResponseSchema, type AtsTailorResponse } from './validation';
// Note: Depending on the specific "@google/genai" library or the fetch REST API used for gemini, implementation varies.
// We are using the standard fetch-based approach for Gemini 1.5 Flash via REST for complete control over system instructions and JSON schemas.

function stripJsonFences(input: string) {
  return input
    .trim()
    .replace(/^```(?:json)?\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

async function delay(ms: number) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

export async function tailorResume(
  originalResume: string,
  jobDescription: string,
  language: 'en' | 'ar',
  strength: 'conservative' | 'balanced' | 'aggressive'
): Promise<AtsTailorResponse> {
  const apiKey = process.env.GEMINI_API_KEY;
  if (!apiKey) throw new Error("GEMINI_API_KEY is not configured.");

  const schemaJson = {
    type: "OBJECT",
    properties: {
      ats_score: { type: "NUMBER" },
      predicted_ats_score: { type: "NUMBER" },
      keywords_matched: { type: "ARRAY", items: { type: "STRING" } },
      keywords_missing: { type: "ARRAY", items: { type: "STRING" } },
      tailored_resume_html: { type: "STRING" },
      feedback: { type: "STRING" }
    },
    required: ["ats_score", "predicted_ats_score", "keywords_matched", "keywords_missing", "tailored_resume_html", "feedback"]
  };

  const systemInstruction = `You are VIGILANTE, an elite, highly precise ATS-optimization AI. Your objective is to brutally scrutinize the original resume against the provided job description and tailor it to bypass Applicant Tracking Systems. Output mathematically precise scores, exact keyword matches, and a highly polished HTML response containing the refined resume. Language context: ${language}. Tailoring aggression: ${strength}. DO NOT hallucinate job titles or experiences the user did not possess. Output MUST comply with the provided JSON schema.`;

  const payload = {
    contents: [{
      parts: [
        { text: `=== JOB DESCRIPTION ===\n${jobDescription}\n\n=== ORIGINAL RESUME ===\n${originalResume}` }
      ]
    }],
    systemInstruction: {
      parts: [{ text: systemInstruction }]
    },
    generationConfig: {
      responseMimeType: "application/json",
      responseSchema: schemaJson,
      temperature: strength === 'aggressive' ? 0.7 : 0.3,
    }
  };

  const models = [
    "gemini-2.5-flash",
    "gemini-flash-latest",
    "gemini-2.5-flash-lite",
    "gemini-pro-latest",
    "gemini-2.0-flash"
  ];
  const maxRetries = 3;
  let lastError: any;

  for (const model of models) {
    console.log(`[Gemini] Attempting tailoring with model: ${model}...`);
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        if (attempt > 0) {
          const waitTime = Math.pow(2, attempt) * 1000;
          console.log(`[Gemini] Retrying with ${model} (Attempt ${attempt}/${maxRetries}) after ${waitTime}ms...`);
          await delay(waitTime);
        }

        const response = await fetch(`https://generativelanguage.googleapis.com/v1beta/models/${model}:generateContent?key=${apiKey}`, {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(payload),
        });

        if (!response.ok) {
          const status = response.status;
          const errText = await response.text();

          if (status === 429) {
            console.warn(`[Gemini] Model ${model} quota exhausted (429). Rotating to next model immediately...`);
            lastError = new Error(`Gemini API 429: ${errText}`);
            break; // Move to next model IMMEDIATELY on 429
          }

          if (status === 503) {
            console.warn(`[Gemini] Model ${model} overloaded (503). ${attempt < maxRetries ? 'Retrying...' : 'Falling back...'}`);
            lastError = new Error(`Gemini API 503: ${errText}`);
            continue; // Retry same model for 503
          }

          throw new Error(`Gemini API Error (${status}): ${errText}`);
        }

        const responseJson = await response.json();
        const rawDataStr = responseJson.candidates?.[0]?.content?.parts?.[0]?.text;

        if (!rawDataStr) {
          throw new Error("Unable to extract valid response parts from Gemini API.");
        }

        let parsed: unknown;
        try {
          parsed = JSON.parse(stripJsonFences(String(rawDataStr)));
        } catch (e) {
          throw new Error(`Gemini returned non-JSON output. ${(e as Error).message}`);
        }

        const validatedData = AtsTailorResponseSchema.parse(parsed);
        return validatedData;

      } catch (err) {
        lastError = err;
        // If it's a fatal error (not 503/429), move to next model
        if (!(err instanceof Error && (err.message.includes('503') || err.message.includes('429')))) {
          break; 
        }
      }
    }
  }

  throw lastError || new Error("Tailoring failed after trying all available models and retries.");
}
